            for sym in section.iter_symbols():
                if sym['st_value'] > 0 and sym['st_info']['type'] in ('STT_FUNC', 'STT_NOTYPE'):
                    funcs.append((sym['st_value'], sym['st_size'], sym.name))
            funcs.sort()
            print(f'  Total func symbols: {len(funcs)}')
            for t in targets:
